sql:
SELECT model_name
FROM car_models
ORDER BY model_name ASC;

SELECT COUNT(sale_id) AS total_sales
FROM car_sales
WHERE model_id = 123;

SELECT model_name, production_year
FROM car_models
ORDER BY production_year DESC;

external_knowledge:
; The query assumes that a car model's production year determines the decade it belongs to; 
; For instance, if a car model's production year is 1995, it would fall under the decade 1990-1999; 
; The decades are predefined in the 'decades' table with 'start_year' and 'end_year' fields.

sql:
SELECT COUNT(*) AS total_models
FROM car_models
WHERE production_year = 2020;

SELECT model_id, COUNT(*) AS total_sales
FROM car_sales
GROUP BY model_id;
